## `unknown` vs `any`

```ts
// WRONG — any disables type checking
catch (e: any) { console.log(e.message); }

// CORRECT — unknown forces narrowing
catch (e: unknown) {
  const msg = e instanceof Error ? e.message : String(e);
  console.error(msg);
}
```

### API / external data
```ts
// WRONG
const data: any = await res.json();
data.user.name; // no type safety

// CORRECT — validate at boundary with Zod
import { z } from 'zod';
const schema = z.object({ user: z.object({ name: z.string() }) });
const data = schema.parse(await res.json()); // throws on mismatch
data.user.name; // fully typed
```

### Type guard pattern
```ts
function isRecord(v: unknown): v is Record<string, unknown> {
  return typeof v === 'object' && v !== null && !Array.isArray(v);
}
```

**Rule:** `any` only in: declaration files, auto-generated code, or documented escape hatches.

## Discriminated Unions

```ts
// WRONG — independent booleans allow impossible states
interface State { loading: boolean; data?: User; error?: string; }

// CORRECT — one discriminant, mutually exclusive states
type AsyncState<T> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error';   error: string };

type UserState = AsyncState<User>;
```

### Usage with exhaustive check
```ts
function render(state: UserState) {
  switch (state.status) {
    case 'idle':    return <Placeholder />;
    case 'loading': return <Spinner />;
    case 'success': return <Profile user={state.data} />; // data typed as User
    case 'error':   return <ErrorBanner msg={state.error} />;
    default: {
      const _exhaustive: never = state; // compile error if case missing
      return null;
    }
  }
}
```

### API response union
```ts
type ApiResult<T> =
  | { ok: true;  data: T }
  | { ok: false; error: string; statusCode: number };

async function fetchUser(id: string): Promise<ApiResult<User>> { ... }

const result = await fetchUser('1');
if (result.ok) {
  result.data; // User — no need to check for undefined
} else {
  result.error; // string
}
```

## Generics + Constraints

```ts
// Basic constraint
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key]; // typed return, no casting
}

// Multiple constraints
function merge<A extends object, B extends object>(a: A, b: B): A & B {
  return { ...a, ...b };
}

// Default generic parameter
function createState<T = string>() { ... }
```

### Conditional types + `infer`
```ts
// Extract promise value type
type Awaited<T> = T extends Promise<infer U> ? U : T;

// Extract array element type
type ElementOf<T> = T extends (infer E)[] ? E : never;

// Unwrap function return
type ReturnOf<T> = T extends (...args: unknown[]) => infer R ? R : never;
```

### Mapped types
```ts
// Make all keys optional + nullable
type Nullable<T> = { [K in keyof T]: T[K] | null };

// Make specific keys required
type RequireFields<T, K extends keyof T> = T & Required<Pick<T, K>>;

// Usage
type CreateUserInput = RequireFields<Partial<User>, 'email'>;
```

## TypeScript Utility Types

```ts
interface User {
  id: string;    name: string;
  email: string; role: 'admin' | 'user';
  createdAt: Date;
}

// Partial<T> — all props optional (update DTOs)
type UpdateUserInput = Partial<User>;

// Required<T> — all props required
type FullUser = Required<User>;

// Pick<T, K> — select subset
type UserCard = Pick<User, 'id' | 'name' | 'role'>;

// Omit<T, K> — exclude keys
type CreateUserInput = Omit<User, 'id' | 'createdAt'>;

// Readonly<T> — immutable
type ImmutableUser = Readonly<User>;

// Record<K, V> — typed map
type RolePermissions = Record<User['role'], string[]>;

// Extract / Exclude on unions
type AdminRole = Extract<User['role'], 'admin'>;  // 'admin'
type NonAdmin  = Exclude<User['role'], 'admin'>;  // 'user'

// ReturnType / Parameters
function fetchUser(id: string): Promise<User> { ... }
type FetchReturn   = Awaited<ReturnType<typeof fetchUser>>; // User
type FetchParams   = Parameters<typeof fetchUser>;          // [string]

// NonNullable
type SafeUser = NonNullable<User | null | undefined>; // User
```

## `satisfies` Operator (TS 4.9+)

### Problem: type annotation widens
```ts
const palette: Record<string, string[]> = {
  red: ['#ff0000', '#cc0000'],
};
palette.red;        // string[] — lost tuple info
palette.nonexistent; // allowed — no error!
```

### Solution: `satisfies` validates without widening
```ts
const palette = {
  red:   ['#ff0000', '#cc0000'],
  green: ['#00ff00'],
  blue:  '#0000ff',           // string, not array — still valid
} satisfies Record<string, string | string[]>;

palette.red;        // string[] — literal type preserved
palette.nonexistent; // ERROR — key not in object
palette.blue.toUpperCase(); // OK — string methods available
```

### Route config pattern
```ts
const routes = {
  home:    { path: '/',        auth: false },
  profile: { path: '/profile', auth: true  },
} satisfies Record<string, { path: string; auth: boolean }>;

routes.home.path;   // '/'
routes.missing;     // ERROR
```

**Rule:** Prefer `satisfies` over `as` when you want type validation but need the literal type preserved.

## Template Literal Types

```ts
// Event name pattern
type EventName<T extends string> = `on${Capitalize<T>}`;
type ButtonEvent = EventName<'click' | 'focus' | 'blur'>;
// 'onClick' | 'onFocus' | 'onBlur'

// API path typing
type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE';
type ApiRoute   = `/api/${string}`;
function request(method: HttpMethod, route: ApiRoute) { ... }
request('GET',  '/api/users');   // OK
request('GONE', '/api/users');   // ERROR — method
request('GET',  '/users');       // ERROR — missing /api prefix

// CSS class combiner
type Size  = 'sm' | 'md' | 'lg';
type Color = 'red' | 'blue' | 'green';
type BtnClass = `btn-${Size}` | `text-${Color}`;

// Intrinsic string manipulation
type ToGetterName<K extends string> = `get${Capitalize<K>}`;
type UserGetters = { [K in keyof User as ToGetterName<K>]: () => User[K] };
// { getId: () => string; getName: () => string; ... }

// Environment variable safety
type EnvKey = 'DATABASE_URL' | 'API_KEY' | 'PORT';
type EnvVars = Record<EnvKey, string>;
```

## Immutability Patterns

```ts
// Readonly interface
interface Config {
  readonly apiUrl: string;
  readonly timeout: number;
}

// Readonly<T> utility
function processUser(user: Readonly<User>) {
  user.name = 'foo'; // ERROR — cannot assign to readonly
  return { ...user, name: 'foo' }; // CORRECT — new object
}

// ReadonlyArray<T>
function sum(nums: ReadonlyArray<number>): number {
  nums.push(1);   // ERROR
  nums.sort();    // ERROR
  return nums.reduce((a, b) => a + b, 0);
}

// as const — literal type narrowing
const ROLES = ['admin', 'user', 'guest'] as const;
type Role = typeof ROLES[number]; // 'admin' | 'user' | 'guest'

const CONFIG = {
  baseUrl: '/api',
  version: 2,
} as const;
type ConfigKeys = keyof typeof CONFIG; // 'baseUrl' | 'version'
CONFIG.version; // type: 2 (not number)

// Deep readonly (use with caution — utility type)
type DeepReadonly<T> = {
  readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K];
};
```
